import { registerRoute, startRouter } from "./modules/router.js"; import { loadTheme, saveTheme } from "./modules/store.js"; import { renderHome, renderProducts, renderProductDetail, renderCart, renderAbout, renderNotFound, updateCartBadge } from "./modules/views.js"; const root = document.documentElement; const themeToggle = document.querySelector("[data-theme-toggle]"); const year = document.querySelector("[data-current-year]"); if (year) { year.textContent = String(new Date().getFullYear()); } initTheme(); updateCartBadge(); registerRoute("/", renderHome); registerRoute("/products", renderProducts); registerRoute("/products/:id", renderProductDetail); registerRoute("/cart", renderCart); registerRoute("/about", renderAbout); startRouter(renderNotFound); function initTheme() { const initialTheme = loadTheme(); setTheme(initialTheme); themeToggle.addEventListener("click", () => { const current = root.getAttribute("data-theme") || "light"; const next = current === "dark" ? "light" : "dark"; setTheme(next); saveTheme(next); }); } function setTheme(theme) { const isDark = theme === "dark"; root.setAttribute("data-theme", theme); themeToggle.textContent = isDark ? "☀️" : "🌙"; themeToggle.setAttribute("aria-pressed", String(isDark)); themeToggle.setAttribute("aria-label", isDark ? "Switch to light theme" : "Switch to dark theme"); }
